ALTER TABLE "global_settings" DROP CONSTRAINT IF EXISTS "global_settings_theme_check";--> statement-breakpoint
ALTER TABLE "global_settings" ADD CONSTRAINT "global_settings_theme_check" CHECK ("global_settings"."theme" IN ('default','dark','minimal','corporate','cyberpunk','elegant','forest','ocean','sunset','pastel','luxury','obsidian','midnight','aurora','nordic','graphite','paper','sage','terracotta','lavender','monochrome','terminal','rose','high-contrast'));
